import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface GameState {
  playerInventory: string[];
  npcRelationships: Record<string, number>;
  currentLocation: string;
  narrativeHistory: string[];
  health: number; // Added for basic game mechanics
}

export interface StoryBeat {
  narrative_text: string;
  image_prompt: string;
  new_state: GameState;
  tension_score: number;
  options: { label: string; action: string }[];
}

export interface GeneratedContent {
  beat: StoryBeat;
  imageUrl?: string;
}

export enum AppStatus {
  SPLASH,
  MENU,
  PLAYING,
  GAME_OVER
}

import { GoogleGenAI, Type } from "@google/genai";
import { GameState, StoryBeat } from "../types";

// Ensure API key is available
const apiKey = process.env.API_KEY;
if (!apiKey) {
  console.error("API_KEY is missing. Please set it in the environment.");
}

const ai = new GoogleGenAI({ apiKey: apiKey || 'dummy-key' });

const STORY_MODEL = "gemini-3-flash-preview";
const IMAGE_MODEL = "gemini-2.5-flash-image";

export const generateInitialState = async (): Promise<StoryBeat> => {
  const prompt = `
    You are the 'Chronos' engine, an infinite text adventure generator.
    Initialize a new sci-fi mystery adventure. 
    The player starts waking up in a cryogenic pod in an abandoned facility.

    Output strictly in JSON format matching the schema.
    The tension_score should be low (1-3) for the start.
    Provide 2-3 initial options for the player.
  `;

  return await generateStoryBeat(prompt, {
    playerInventory: [],
    npcRelationships: {},
    currentLocation: "Unknown Facility",
    narrativeHistory: [],
    health: 100
  });
};

export const generateNextBeat = async (
  choice: string,
  currentState: GameState
): Promise<StoryBeat> => {
  const prompt = `
    You are the 'Chronos' engine.
    Current State: ${JSON.stringify(currentState)}
    Player Choice: "${choice}"

    Generate the next narrative beat based on the choice and current state.
    Update the inventory, relationships, and location as logical consequences of the action.
    Update narrativeHistory by appending a 1-sentence summary of the PREVIOUS event, keeping only the last 5.

    The 'tension_score' (1-10) is CRITICAL. 
    1-4: Calm, exploration.
    5-7: Unease, rising action, minor conflict.
    8-10: Immediate danger, cliffhanger, major revelation.

    Provide 2-4 distinct options for the user to proceed.
  `;

  return await generateStoryBeat(prompt, currentState);
};

const generateStoryBeat = async (prompt: string, currentState: GameState): Promise<StoryBeat> => {
  try {
    const response = await ai.models.generateContent({
      model: STORY_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            narrative_text: { type: Type.STRING, description: "The main story text to display. Be atmospheric and cinematic." },
            image_prompt: { type: Type.STRING, description: "A detailed visual description of the current scene for an image generator. No text in image." },
            new_state: {
              type: Type.OBJECT,
              properties: {
                playerInventory: { type: Type.ARRAY, items: { type: Type.STRING } },
                npcRelationships: { type: Type.OBJECT, additionalProperties: { type: Type.NUMBER } }, // Note: simple object for Record<string, number>
                currentLocation: { type: Type.STRING },
                narrativeHistory: { type: Type.ARRAY, items: { type: Type.STRING } },
                health: { type: Type.NUMBER }
              },
              required: ["playerInventory", "currentLocation", "narrativeHistory", "health"],
            },
            tension_score: { type: Type.NUMBER, description: "1 to 10 score indicating dramatic tension." },
            options: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  label: { type: Type.STRING },
                  action: { type: Type.STRING }
                },
                required: ["label", "action"]
              }
            }
          },
          required: ["narrative_text", "image_prompt", "new_state", "tension_score", "options"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No text response from Gemini");

    return JSON.parse(text) as StoryBeat;

  } catch (error) {
    console.error("Error generating story beat:", error);
    // Fallback in case of error to prevent app crash
    return {
      narrative_text: "The Chronos engine flickers. Connectivity to the timeline is lost momentarily. You wait...",
      image_prompt: "Static interference on a digital screen, dark atmosphere",
      new_state: currentState,
      tension_score: 1,
      options: [{ label: "Retry Connection", action: "retry" }]
    };
  }
};

export const generateSceneImage = async (imagePrompt: string): Promise<string | null> => {
  try {
    const response = await ai.models.generateContent({
      model: IMAGE_MODEL,
      contents: {
        parts: [{ text: imagePrompt + " cinematic lighting, 8k resolution, photorealistic, sci-fi style, atmospheric" }]
      },
      config: {
        // Nano Banana / Flash Image doesn't support responseMimeType in the same way, 
        // but returns inlineData or we just extract it.
      }
    });

    // Check for inline data in the response parts
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData && part.inlineData.data) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.warn("Failed to generate image:", error);
    return null;
  }
};

import React, { createContext, useContext, useState, useEffect } from 'react';

interface MonetizationContextType {
  isPremium: boolean;
  isAdShowing: boolean;
  purchasePremium: () => void;
  showRewardedAd: (onComplete: () => void) => void;
}

const MonetizationContext = createContext<MonetizationContextType | undefined>(undefined);

export const MonetizationProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [isPremium, setIsPremium] = useState(false);
  const [isAdShowing, setIsAdShowing] = useState(false);

  // Load persistence
  useEffect(() => {
    const storedPremium = localStorage.getItem('chronos_premium');
    if (storedPremium === 'true') {
      setIsPremium(true);
    }
  }, []);

  const purchasePremium = () => {
    // Mock purchase logic
    setIsPremium(true);
    localStorage.setItem('chronos_premium', 'true');
  };

  const showRewardedAd = (onComplete: () => void) => {
    if (isPremium) {
      onComplete();
      return;
    }

    setIsAdShowing(true);
    // Mock Ad Duration
    setTimeout(() => {
      setIsAdShowing(false);
      onComplete();
    }, 5000); // 5 second ad
  };

  return (
    <MonetizationContext.Provider value={{ isPremium, isAdShowing, purchasePremium, showRewardedAd }}>
      {children}
    </MonetizationContext.Provider>
  );
};

export const useMonetization = () => {
  const context = useContext(MonetizationContext);
  if (!context) throw new Error("useMonetization must be used within MonetizationProvider");
  return context;
};

import React, { createContext, useContext, useState } from 'react';
import { GameState, StoryBeat, AppStatus } from '../types';
import { generateInitialState, generateNextBeat, generateSceneImage } from '../services/geminiService';

interface GameContextType {
  gameState: GameState | null;
  currentBeat: StoryBeat | null;
  currentImage: string | null;
  appStatus: AppStatus;
  isLoading: boolean;
  startGame: () => void;
  makeChoice: (choice: string) => void;
  resetGame: () => void;
}

const GameContext = createContext<GameContextType | undefined>(undefined);

// Default placeholder image if generation fails or while loading first time
const PLACEHOLDER_IMG = "https://picsum.photos/1080/1920?grayscale&blur=2";

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [gameState, setGameState] = useState<GameState | null>(null);
  const [currentBeat, setCurrentBeat] = useState<StoryBeat | null>(null);
  const [currentImage, setCurrentImage] = useState<string | null>(null);
  const [appStatus, setAppStatus] = useState<AppStatus>(AppStatus.SPLASH);
  const [isLoading, setIsLoading] = useState(false);

  const startGame = async () => {
    setIsLoading(true);
    try {
      const beat = await generateInitialState();
      setGameState(beat.new_state);
      setCurrentBeat(beat);
      setAppStatus(AppStatus.PLAYING);

      // Async load image without blocking UI text
      generateSceneImage(beat.image_prompt).then(img => {
        if (img) setCurrentImage(img);
      });
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const makeChoice = async (choice: string) => {
    if (!gameState) return;

    setIsLoading(true);
    // Optimistic UI could happen here, but for story generation we usually wait
    try {
      const nextBeat = await generateNextBeat(choice, gameState);
      setGameState(nextBeat.new_state);
      setCurrentBeat(nextBeat);

      // Fetch image in background
      generateSceneImage(nextBeat.image_prompt).then(img => {
        if (img) setCurrentImage(img);
      });

    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const resetGame = () => {
    setGameState(null);
    setCurrentBeat(null);
    setCurrentImage(null);
    setAppStatus(AppStatus.MENU);
  };

  return (
    <GameContext.Provider value={{
      gameState,
      currentBeat,
      currentImage,
      appStatus,
      isLoading,
      startGame,
      makeChoice,
      resetGame
    }}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within GameProvider");
  return context;
};

// Helper to expose setter for SplashScreen
export const useGameDispatch = () => {
    const context = useContext(GameContext);
    // We can cast or extend if we need direct state setters, but for now specific methods work.
    // However, we need to set AppStatus from Splash.
    // Let's just return the context.
    return context;
}

