import React from 'react';
import { useMonetization } from '../context/MonetizationContext';

interface TensionGateProps {
  tensionScore: number;
  children: React.ReactNode;
}

export const TensionGate: React.FC<TensionGateProps> = ({ tensionScore, children }) => {
  const { isPremium, showRewardedAd } = useMonetization();
  const [isUnlocked, setIsUnlocked] = React.useState(false);

  // Reset unlock state when tension drops or children change (implies new beat)
  // We need a stable way to know if it's a new beat. 
  // In a real app we might track beat IDs. Here we assume if tension is high, we lock.
  // We'll use a local state that persists only until the component unmounts/remounts or tension changes?
  // A better way: If tensionScore > 7 and !isPremium and !isUnlocked, show lock.

  // We need to reset isUnlocked when the story moves forward.
  // This component will likely be re-rendered with new props on new beat.
  // If we rely on key={beatIndex} in parent, state resets automatically.

  const isLocked = tensionScore > 7 && !isPremium && !isUnlocked;

  const handleUnlock = () => {
    showRewardedAd(() => {
      setIsUnlocked(true);
    });
  };

  return (
    <div className="relative w-full h-full">
      {/* Content Layer - blurred if locked */}
      <div className={`transition-all duration-700 ease-in-out ${isLocked ? 'blur-md opacity-50 grayscale' : 'blur-0 opacity-100'}`}>
        {children}
      </div>

      {/* Lock Overlay */}
      {isLocked && (
        <div className="absolute inset-0 flex flex-col items-center justify-center z-20 p-6">
          <div className="glass-panel p-8 rounded-2xl max-w-md text-center shadow-2xl border border-red-500/30">
            <div className="text-4xl mb-4">🔒</div>
            <h3 className="text-2xl font-bold text-red-400 mb-2 cinematic-text">High Tension Detected</h3>
            <p className="text-gray-300 mb-6">The story has reached a critical cliffhanger. Unlock the next moments.</p>

            <button 
              onClick={handleUnlock}
              className="px-8 py-3 bg-gradient-to-r from-red-600 to-orange-600 text-white font-bold rounded-full hover:scale-105 transition-transform shadow-[0_0_20px_rgba(220,38,38,0.5)]"
            >
              Unlock Chapter (Watch Ad)
            </button>
            <p className="mt-4 text-xs text-gray-500">Or upgrade to Premium to skip this.</p>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';

export const AdOverlay: React.FC = () => {
  const [timeLeft, setTimeLeft] = useState(5);

  useEffect(() => {
    const timer = setInterval(() => {
      setTimeLeft((prev) => {
        if (prev <= 1) {
          clearInterval(timer);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center">
      <div className="w-full max-w-md bg-white text-black p-6 rounded-lg shadow-xl text-center">
        <h2 className="text-xl font-bold mb-4">Advertisement</h2>
        <div className="w-full h-48 bg-gray-200 mb-4 flex items-center justify-center text-gray-400 rounded">
          [Video Placeholder]
        </div>
        <p className="mb-4">Reward granting in {timeLeft} seconds...</p>
        <div className="w-full bg-gray-200 h-2 rounded-full overflow-hidden">
          <div 
            className="h-full bg-blue-600 transition-all duration-1000 ease-linear"
            style={{ width: `${((5 - timeLeft) / 5) * 100}%` }}
          />
        </div>
      </div>
    </div>
  );
};

