import React, { useEffect, useRef } from 'react';
import { useGame } from '../context/GameContext';
import { TensionGate } from './TensionGate';
import { useMonetization } from '../context/MonetizationContext';

export const StoryView: React.FC = () => {
  const { currentBeat, makeChoice, isLoading, currentImage, gameState } = useGame();
  const { isPremium } = useMonetization();
  const bottomRef = useRef<HTMLDivElement>(null);

  // Auto scroll to bottom of text when it updates
  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [currentBeat]);

  if (!currentBeat || !gameState) return null;

  return (
    <div className="relative w-full h-full overflow-hidden flex flex-col">
      {/* Background Layer */}
      <div className="absolute inset-0 z-0">
        <div className="absolute inset-0 bg-black/60 z-10" /> {/* Dark overlay for text readability */}
        {currentImage ? (
           <img 
             src={currentImage} 
             alt="Scene background" 
             className="w-full h-full object-cover transition-opacity duration-1000 ease-in-out opacity-100"
           />
        ) : (
          <div className="w-full h-full bg-gray-900 animate-pulse" />
        )}
      </div>

      {/* Header / Stats */}
      <div className="relative z-20 p-4 flex justify-between items-start bg-gradient-to-b from-black/80 to-transparent">
        <div className="flex gap-4 text-xs tracking-widest text-gray-300">
           <div>LOC: {gameState.currentLocation}</div>
           <div>HP: {gameState.health}%</div>
        </div>
        {!isPremium && (
          <div className="text-xs text-yellow-500 border border-yellow-500/50 px-2 py-1 rounded">
            FREE VERSION
          </div>
        )}
      </div>

      {/* Main Content Area */}
      <div className="relative z-10 flex-1 flex flex-col justify-end p-6 pb-24 md:p-12 md:pb-32 overflow-y-auto">
         {/* Tension Gate wraps the narrative content to obscure it if needed */}
         {/* Note: We force a re-render of TensionGate when beat changes by using a key, 
             so the lock state resets correctly for new beats. */}
         <TensionGate key={currentBeat.narrative_text.substring(0, 10)} tensionScore={currentBeat.tension_score}>
            <div className="max-w-3xl mx-auto space-y-6">
              {/* Previous History Context (Faded) */}
              {gameState.narrativeHistory.length > 0 && (
                <div className="text-gray-500 text-sm italic mb-8 border-l-2 border-gray-700 pl-4">
                  {gameState.narrativeHistory[gameState.narrativeHistory.length - 1]}
                </div>
              )}

              {/* Main Text */}
              <p className="text-xl md:text-2xl lg:text-3xl leading-relaxed font-serif text-shadow-lg text-white drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)]">
                {currentBeat.narrative_text}
              </p>

              <div ref={bottomRef} />
            </div>
         </TensionGate>
      </div>

      {/* Choices Area - Sticky Bottom */}
      <div className="absolute bottom-0 left-0 right-0 z-30 p-6 bg-gradient-to-t from-black via-black/90 to-transparent">
        <div className="max-w-3xl mx-auto flex flex-col gap-3">
          {isLoading ? (
            <div className="flex items-center justify-center gap-2 text-indigo-400 animate-pulse py-4">
               <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}/>
               <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}/>
               <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}/>
               <span className="text-sm tracking-widest uppercase">Chronos is thinking</span>
            </div>
          ) : (
            currentBeat.options.map((opt, idx) => (
              <button
                key={idx}
                onClick={() => makeChoice(opt.action)}
                className="w-full text-left p-4 rounded-xl glass-panel hover:bg-white/10 transition-all duration-300 border-l-4 border-transparent hover:border-indigo-500 group"
              >
                <span className="block text-sm text-gray-400 mb-1 group-hover:text-indigo-300 transition-colors">OPTION {idx + 1}</span>
                <span className="text-lg font-medium">{opt.label}</span>
              </button>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { GameProvider, useGame } from './context/GameContext';
import { MonetizationProvider, useMonetization } from './context/MonetizationContext';
import { SplashScreen } from './components/SplashScreen';
import { StoryView } from './components/StoryView';
import { Paywall } from './components/Paywall';
import { AdOverlay } from './components/AdOverlay';
import { AppStatus } from './types';

const GameContent: React.FC = () => {
  const { appStatus, startGame, resetGame } = useGame();
  const { isAdShowing, isPremium } = useMonetization();
  const [showPaywall, setShowPaywall] = useState(false);
  const [showSplash, setShowSplash] = useState(true);

  // Handle Splash Screen Logic
  useEffect(() => {
    const timer = setTimeout(() => {
      setShowSplash(false);
    }, 2500); // 2.5s splash
    return () => clearTimeout(timer);
  }, []);

  if (showSplash) {
    return <SplashScreen />;
  }

  if (appStatus === AppStatus.MENU || appStatus === AppStatus.SPLASH) {
     return (
       <div className="relative w-full h-screen bg-black flex flex-col items-center justify-center overflow-hidden">
         {/* Abstract BG */}
         <div className="absolute inset-0 bg-[url('https://picsum.photos/1920/1080?grayscale&blur=8')] bg-cover opacity-30" />

         <div className="z-10 text-center space-y-8 p-4">
           <h1 className="text-6xl md:text-8xl font-bold cinematic-text text-white tracking-tighter mb-4">CHRONOS</h1>
           <p className="text-xl text-gray-400 max-w-md mx-auto">Infinite possibilities. One timeline. Yours.</p>

           <div className="flex flex-col gap-4 w-full max-w-xs mx-auto">
             <button 
               onClick={startGame}
               className="w-full py-4 bg-white text-black font-bold tracking-widest hover:bg-gray-200 transition-colors rounded-sm"
             >
               BEGIN STORY
             </button>

             {!isPremium && (
                <button 
                  onClick={() => setShowPaywall(true)}
                  className="w-full py-4 border border-white/20 text-white hover:bg-white/10 transition-colors rounded-sm text-sm tracking-widest"
                >
                  REMOVE ADS
                </button>
             )}
           </div>
         </div>

         {showPaywall && <Paywall onClose={() => setShowPaywall(false)} />}
       </div>
     );
  }

  return (
    <div className="w-full h-screen bg-black">
      <StoryView />
      {/* Settings / Menu Button Top Right */}
      <div className="fixed top-4 right-4 z-40">
        <button 
          onClick={resetGame}
          className="w-10 h-10 flex items-center justify-center rounded-full bg-black/50 hover:bg-black/80 text-white border border-white/20"
        >
          ✕
        </button>
      </div>

      {/* Global Overlays */}
      {isAdShowing && <AdOverlay />}
    </div>
  );
};

const App: React.FC = () => {
  return (
    <MonetizationProvider>
      <GameProvider>
        <GameContent />
      </GameProvider>
    </MonetizationProvider>
  );
};

export default App;

export interface GameState {
  playerInventory: string[];
  npcRelationships: { name: string; score: number }[];
  currentLocation: string;
  narrativeHistory: string[];
  health: number; // Added for basic game mechanics
}

export interface StoryBeat {
  narrative_text: string;
  image_prompt: string;
  new_state: GameState;
  tension_score: number;
  options: { label: string; action: string }[];
}

export interface GeneratedContent {
  beat: StoryBeat;
  imageUrl?: string;
}

export enum AppStatus {
  SPLASH,
  MENU,
  PLAYING,
  GAME_OVER
}

import { GoogleGenAI, Type } from "@google/genai";
import { GameState, StoryBeat } from "../types";

// Ensure API key is available
const apiKey = process.env.API_KEY;
if (!apiKey) {
  console.error("API_KEY is missing. Please set it in the environment.");
}

const ai = new GoogleGenAI({ apiKey: apiKey || 'dummy-key' });

const STORY_MODEL = "gemini-3-flash-preview";
const IMAGE_MODEL = "gemini-2.5-flash-image";

export const generateInitialState = async (): Promise<StoryBeat> => {
  const prompt = `
    You are the 'Chronos' engine, an infinite text adventure generator.
    Initialize a new sci-fi mystery adventure. 
    The player starts waking up in a cryogenic pod in an abandoned facility.

    Output strictly in JSON format matching the schema.
    The tension_score should be low (1-3) for the start.
    Provide 2-3 initial options for the player.
  `;

  return await generateStoryBeat(prompt, {
    playerInventory: [],
    npcRelationships: [],
    currentLocation: "Unknown Facility",
    narrativeHistory: [],
    health: 100
  });
};

export const generateNextBeat = async (
  choice: string,
  currentState: GameState
): Promise<StoryBeat> => {
  const prompt = `
    You are the 'Chronos' engine.
    Current State: ${JSON.stringify(currentState)}
    Player Choice: "${choice}"

    Generate the next narrative beat based on the choice and current state.
    Update the inventory, relationships, and location as logical consequences of the action.
    Update narrativeHistory by appending a 1-sentence summary of the PREVIOUS event, keeping only the last 5.

    The 'tension_score' (1-10) is CRITICAL. 
    1-4: Calm, exploration.
    5-7: Unease, rising action, minor conflict.
    8-10: Immediate danger, cliffhanger, major revelation.

    Provide 2-4 distinct options for the user to proceed.
  `;

  return await generateStoryBeat(prompt, currentState);
};

const generateStoryBeat = async (prompt: string, currentState: GameState): Promise<StoryBeat> => {
  try {
    const response = await ai.models.generateContent({
      model: STORY_MODEL,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            narrative_text: { type: Type.STRING, description: "The main story text to display. Be atmospheric and cinematic." },
            image_prompt: { type: Type.STRING, description: "A detailed visual description of the current scene for an image generator. No text in image." },
            new_state: {
              type: Type.OBJECT,
              properties: {
                playerInventory: { type: Type.ARRAY, items: { type: Type.STRING } },
                npcRelationships: { 
                  type: Type.ARRAY, 
                  items: { 
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      score: { type: Type.NUMBER }
                    },
                    required: ["name", "score"]
                  } 
                },
                currentLocation: { type: Type.STRING },
                narrativeHistory: { type: Type.ARRAY, items: { type: Type.STRING } },
                health: { type: Type.NUMBER }
              },
              required: ["playerInventory", "currentLocation", "narrativeHistory", "health", "npcRelationships"],
            },
            tension_score: { type: Type.NUMBER, description: "1 to 10 score indicating dramatic tension." },
            options: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  label: { type: Type.STRING },
                  action: { type: Type.STRING }
                },
                required: ["label", "action"]
              }
            }
          },
          required: ["narrative_text", "image_prompt", "new_state", "tension_score", "options"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No text response from Gemini");

    return JSON.parse(text) as StoryBeat;

  } catch (error) {
    console.error("Error generating story beat:", error);
    // Fallback in case of error to prevent app crash
    return {
      narrative_text: "The Chronos engine flickers. Connectivity to the timeline is lost momentarily. You wait...",
      image_prompt: "Static interference on a digital screen, dark atmosphere",
      new_state: currentState,
      tension_score: 1,
      options: [{ label: "Retry Connection", action: "retry" }]
    };
  }
};

export const generateSceneImage = async (imagePrompt: string): Promise<string | null> => {
  try {
    const response = await ai.models.generateContent({
      model: IMAGE_MODEL,
      contents: {
        parts: [{ text: imagePrompt + " cinematic lighting, 8k resolution, photorealistic, sci-fi style, atmospheric" }]
      },
      config: {
        // Nano Banana / Flash Image doesn't support responseMimeType in the same way, 
        // but returns inlineData or we just extract it.
      }
    });

    // Check for inline data in the response parts
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData && part.inlineData.data) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.warn("Failed to generate image:", error);
    return null;
  }
};

import React, { useEffect, useRef } from 'react';
import { useGame } from '../context/GameContext';
import { TensionGate } from './TensionGate';
import { useMonetization } from '../context/MonetizationContext';

export const StoryView: React.FC = () => {
  const { currentBeat, makeChoice, isLoading, currentImage, gameState } = useGame();
  const { isPremium } = useMonetization();
  const bottomRef = useRef<HTMLDivElement>(null);

  // Auto scroll to bottom of text when it updates
  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [currentBeat]);

  if (!currentBeat || !gameState) return null;

  return (
    <div className="relative w-full h-full overflow-hidden flex flex-col">
      {/* Background Layer */}
      <div className="absolute inset-0 z-0">
        <div className="absolute inset-0 bg-black/60 z-10" /> {/* Dark overlay for text readability */}
        {currentImage ? (
           <img 
             src={currentImage} 
             alt="Scene background" 
             className="w-full h-full object-cover transition-opacity duration-1000 ease-in-out opacity-100"
           />
        ) : (
          <div className="w-full h-full bg-gray-900 animate-pulse" />
        )}
      </div>

      {/* Header / Stats */}
      <div className="relative z-20 p-4 flex justify-between items-start bg-gradient-to-b from-black/80 to-transparent">
        <div className="flex gap-4 text-xs tracking-widest text-gray-300">
           <div>LOC: {gameState.currentLocation}</div>
           <div>HP: {gameState.health}%</div>
        </div>
        {!isPremium && (
          <div className="text-xs text-yellow-500 border border-yellow-500/50 px-2 py-1 rounded">
            FREE VERSION
          </div>
        )}
      </div>

      {/* Main Content Area */}
      <div className="relative z-10 flex-1 flex flex-col justify-end p-6 pb-24 md:p-12 md:pb-32 overflow-y-auto">
         {/* Tension Gate wraps the narrative content to obscure it if needed */}
         {/* Note: We force a re-render of TensionGate when beat changes by using a key, 
             so the lock state resets correctly for new beats. */}
         <TensionGate key={currentBeat.narrative_text.substring(0, 10)} tensionScore={currentBeat.tension_score}>
            <div className="max-w-4xl mx-auto space-y-6">
              {/* Previous History Context (Faded) */}
              {gameState.narrativeHistory.length > 0 && (
                <div className="text-gray-400 text-sm md:text-base italic mb-8 border-l-2 border-gray-600 pl-4 opacity-70">
                  {gameState.narrativeHistory[gameState.narrativeHistory.length - 1]}
                </div>
              )}

              {/* Main Text */}
              <p 
                className="text-2xl md:text-3xl lg:text-4xl leading-loose font-serif text-white animate-fade-in-up tracking-wide"
                style={{ 
                  textShadow: '0 4px 8px rgba(0,0,0,1), 0 2px 4px rgba(0,0,0,1), 0 0 40px rgba(0,0,0,0.8)' 
                }}
              >
                {currentBeat.narrative_text}
              </p>

              <div ref={bottomRef} />
            </div>
         </TensionGate>
      </div>

      {/* Choices Area - Sticky Bottom */}
      <div className="absolute bottom-0 left-0 right-0 z-30 p-6 bg-gradient-to-t from-black via-black/90 to-transparent">
        <div className="max-w-3xl mx-auto flex flex-col gap-3">
          {isLoading ? (
            <div className="flex items-center justify-center gap-2 text-indigo-400 animate-pulse py-4">
               <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}/>
               <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}/>
               <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}/>
               <span className="text-sm tracking-widest uppercase">Chronos is thinking</span>
            </div>
          ) : (
            currentBeat.options.map((opt, idx) => (
              <button
                key={idx}
                onClick={() => makeChoice(opt.action)}
                className="w-full text-left p-4 rounded-xl glass-panel hover:bg-white/10 transition-all duration-300 border-l-4 border-transparent hover:border-indigo-500 group"
              >
                <span className="block text-sm text-gray-400 mb-1 group-hover:text-indigo-300 transition-colors">OPTION {idx + 1}</span>
                <span className="text-lg font-medium">{opt.label}</span>
              </button>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

