                >
                  REMOVE ADS
                </button>
             )}
           </div>
         </div>

         {showPaywallModal && <Paywall onClose={closePaywall} />}
       </div>
     );
  }

  return (
    <div className="w-full h-screen bg-black">
      <StoryView />
      {/* Settings / Menu Button Top Right */}
      <div className="fixed top-4 right-4 z-40">
        <button 
          onClick={resetGame}
