        ))}
      </div>

      {/* Back Button */}
      <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-20">
         <button 
           onClick={resetGame}
           className="px-8 py-3 rounded-full border border-white/20 text-gray-400 hover:text-white hover:bg-white/10 hover:border-white/40 transition-all text-xs tracking-[0.2em] uppercase backdrop-blur-md bg-black/50"
         >
           Return to Menu
         </button>
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { useGame } from '../context/GameContext';
import { TensionGate } from './TensionGate';
import { useMonetization } from '../context/MonetizationContext';

export const StoryView: React.FC = () => {
  const { currentBeat, makeChoice, isLoading, currentImage, gameState } = useGame();
  const { isPremium, showRewardedAd } = useMonetization();

  // Local state to track ad unlocks for specific cliffhangers
  const [isAdUnlocked, setIsAdUnlocked] = useState(false);
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  // Reset ad unlock state when moving to a new beat
  useEffect(() => {
    setIsAdUnlocked(false);
  }, [currentBeat]);

  // Scroll to top of the content area whenever the beat changes to ensure readability from start
  useEffect(() => {
    if (scrollContainerRef.current && !isLoading) {
        scrollContainerRef.current.scrollTop = 0;
    }
  }, [currentBeat, isLoading]);

  if (!currentBeat || !gameState) return null;

  // Determine Lock Status
  const isCliffhanger = currentBeat.tension_score > 7;
  const isLocked = isCliffhanger && !isPremium && !isAdUnlocked;

  // Handler for Ad Unlock
  const handleUnlockAd = () => {
    showRewardedAd(() => {
      setIsAdUnlocked(true);
    });
  };

  // Generate a stable key for the beat to trigger animations
  // Using a segment of the text ensures uniqueness even if location is static
  const beatKey = `${gameState.currentLocation}_${currentBeat.narrative_text.substring(0, 15)}`;

  return (
    <div className="relative w-full h-full overflow-hidden flex flex-col bg-black">
      {/* Background Layer - Absolute behind everything */}
      <div className="absolute inset-0 z-0 overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-t from-black via-black/40 to-black/30 z-10" /> 
        {currentImage ? (
           <img 
             key={currentImage}
             src={currentImage} 
             alt="Scene background" 
             className="w-full h-full object-cover animate-bg-enter opacity-0" 
           />
        ) : (
          <div className="w-full h-full relative overflow-hidden flex items-center justify-center bg-gray-950">
             {/* Subtle Radial Pulse Background */}
             <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-900/20 via-gray-950 to-black animate-pulse" style={{ animationDuration: '4s' }} />

             {/* Loading Indicator */}
             <div className="z-10 flex flex-col items-center gap-4 opacity-50">
                 <div className="w-12 h-12 border-2 border-indigo-500/10 border-t-indigo-500/50 rounded-full animate-spin duration-1000"></div>
                 <span className="text-[10px] uppercase tracking-[0.4em] text-indigo-300/40 font-light animate-pulse">Visualizing</span>
             </div>
          </div>
        )}
      </div>

      {/* Main Layout - Flex Column to manage vertical space and prevent overlap */}
      <div className="relative z-10 flex flex-col h-full w-full max-w-5xl mx-auto">

        {/* Header - Fixed Height */}
        <div className="flex-none p-4 flex justify-between items-start bg-gradient-to-b from-black via-black/60 to-transparent">
            <div className="flex gap-4 text-xs tracking-[0.2em] font-semibold text-gray-400 uppercase">
            <div className="flex items-center"><span className="w-2 h-2 bg-indigo-500 rounded-full mr-2 animate-pulse"></span> {gameState.currentLocation}</div>
            <div>HP // <span className={gameState.health < 30 ? "text-red-500" : "text-emerald-400"}>{gameState.health}%</span></div>
            </div>
            {!isPremium && (
            <div className="text-[10px] tracking-widest text-yellow-500 border border-yellow-500/30 bg-yellow-500/10 px-2 py-1 rounded">
                LIMITED ACCESS
            </div>
            )}
        </div>

        {/* Scrollable Story Area - Flex-1 (Takes remaining space) */}
        <div 
            ref={scrollContainerRef}
            className="flex-1 overflow-y-auto no-scrollbar px-6 md:px-12 py-4"
        >
            <TensionGate 
                key={beatKey} 
                isLocked={isLocked} 
                onUnlockAd={handleUnlockAd}
            >
                <div className={`space-y-8 pb-8 transition-all duration-700 ${isLoading ? 'opacity-40 blur-sm scale-[0.99]' : 'opacity-100 scale-100'}`}>
                    {/* Previous History Context */}
                    {gameState.narrativeHistory.length > 0 && (
                        <div className="mb-8 opacity-0 animate-[slideDownFade_1s_ease-out_0.2s_forwards] flex flex-col items-start gap-2">
                            <div className="flex items-center gap-3">
                                <div className="h-px w-6 bg-indigo-500/50"></div>
                                <span className="text-[10px] uppercase tracking-[0.25em] text-indigo-400/80 font-sans">System Log</span>
                            </div>
                            <p className="text-gray-400/80 text-sm font-sans font-light leading-relaxed pl-9 border-l border-indigo-500/10">
                                "{gameState.narrativeHistory[gameState.narrativeHistory.length - 1]}"
                            </p>
                        </div>
                    )}

                    {/* Main Narrative Text */}
                    <p 
                        key={currentBeat.narrative_text}
                        className="text-xl md:text-2xl lg:text-3xl leading-[1.8] font-serif text-gray-100 animate-cinematic-reveal tracking-wide"
                        style={{ 
                        textShadow: '0 2px 10px rgba(0,0,0,0.9), 0 0 30px rgba(0,0,0,0.5)' 
                        }}
                    >
                        {currentBeat.narrative_text}
                    </p>
                </div>
            </TensionGate>
        </div>

        {/* Choices Footer - Fixed Height (Auto based on content) - In Flow to prevent overlap */}
        <div className="flex-none p-6 pt-12 bg-gradient-to-t from-black via-black/95 to-transparent">
            <div className={`flex flex-col gap-3 transition-all duration-500 ${isLocked ? 'opacity-0 pointer-events-none translate-y-10' : 'opacity-100 animate-options-reveal'}`}>
            {isLoading ? (
                <div className="flex items-center justify-center gap-3 text-indigo-300/80 py-6">
                <div className="flex gap-1">
                    <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce" style={{ animationDuration: '1s', animationDelay: '0ms' }}/>
                    <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce" style={{ animationDuration: '1s', animationDelay: '200ms' }}/>
                    <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce" style={{ animationDuration: '1s', animationDelay: '400ms' }}/>
                </div>
                <span className="text-xs tracking-[0.3em] uppercase">Simulating Timeline</span>
                </div>
            ) : (
                currentBeat.options.map((opt, idx) => (
                <button
                    key={idx}
                    onClick={() => makeChoice(opt.action)}
                    className="w-full text-left p-4 md:p-5 rounded-lg glass-panel hover:bg-white/10 hover:border-indigo-400/50 transition-all duration-300 border-l-2 border-transparent hover:scale-[1.02] hover:shadow-[0_0_25px_rgba(99,102,241,0.25)] group relative overflow-hidden"
                >
                    <div className="absolute inset-0 bg-indigo-500/0 group-hover:bg-indigo-500/5 transition-colors duration-500" />
                    <span className="block text-[10px] tracking-[0.2em] text-gray-500 mb-1 md:mb-2 group-hover:text-indigo-300 transition-colors uppercase">Intervention {idx + 1}</span>
                    <span className="text-base md:text-lg lg:text-xl font-medium text-gray-200 group-hover:text-white font-serif">{opt.label}</span>
                </button>
                ))
            )}
            </div>
        </div>
      </div>
    </div>
  );
};

export interface GameState {
  playerInventory: string[];
  npcRelationships: { name: string; score: number }[];
  currentLocation: string;
  narrativeHistory: string[];
  health: number; // Added for basic game mechanics
}

export type StoryTheme = 'scifi' | 'fantasy' | 'horror' | 'cyberpunk' | 'postapocalyptic';

export interface StoryBeat {
  narrative_text: string;
  image_prompt: string;
  new_state: GameState;
  tension_score: number;
  options: { label: string; action: string }[];
}

export interface GeneratedContent {
  beat: StoryBeat;
  imageUrl?: string;
}

export interface SaveData {
  gameState: GameState;
  currentBeat: StoryBeat;
  currentImage: string | null;
  selectedTheme: StoryTheme;
  timestamp: number;
}

export enum AppStatus {
  SPLASH,
  MENU,
  THEME_SELECT,
  PLAYING,
  GAME_OVER
}

import React, { createContext, useContext, useState, useEffect } from 'react';
import { GameState, StoryBeat, AppStatus, StoryTheme, SaveData } from '../types';
import { generateInitialState, generateNextBeat, generateSceneImage } from '../services/geminiService';

interface GameContextType {
  gameState: GameState | null;
  currentBeat: StoryBeat | null;
  currentImage: string | null;
  appStatus: AppStatus;
  isLoading: boolean;
  selectedTheme: StoryTheme;
  hasSave: boolean;
  enterThemeSelection: () => void;
  startGame: (theme: StoryTheme) => void;
  makeChoice: (choice: string) => void;
  resetGame: () => void;
  saveGame: () => void;
  loadGame: () => void;
}

const GameContext = createContext<GameContextType | undefined>(undefined);

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [gameState, setGameState] = useState<GameState | null>(null);
  const [currentBeat, setCurrentBeat] = useState<StoryBeat | null>(null);
  const [currentImage, setCurrentImage] = useState<string | null>(null);
  const [appStatus, setAppStatus] = useState<AppStatus>(AppStatus.SPLASH);
  const [isLoading, setIsLoading] = useState(false);
  const [selectedTheme, setSelectedTheme] = useState<StoryTheme>('scifi');
  const [hasSave, setHasSave] = useState(false);

  // Check for existing save on mount
  useEffect(() => {
    const saveExists = !!localStorage.getItem('chronos_save');
    setHasSave(saveExists);
  }, []);

  const enterThemeSelection = () => {
    setAppStatus(AppStatus.THEME_SELECT);
  };

  const startGame = async (theme: StoryTheme) => {
    setSelectedTheme(theme);
    setIsLoading(true);
    setCurrentImage(null); // Clear image for initial load
    // Transition to playing immediately to show loading spinner in the game view
    setAppStatus(AppStatus.PLAYING); 

    try {
      const beat = await generateInitialState(theme);
      setGameState(beat.new_state);
      setCurrentBeat(beat);

      // Async load image without blocking UI text
      generateSceneImage(beat.image_prompt).then(img => {
        if (img) setCurrentImage(img);
      });
    } catch (e) {
      console.error(e);
      setAppStatus(AppStatus.THEME_SELECT); // Go back if error
    } finally {
      setIsLoading(false);
    }
  };

  const makeChoice = async (choice: string) => {
    if (!gameState) return;

    setIsLoading(true);
    setCurrentImage(null); // Clear image to show shimmer during transition
    try {
      const nextBeat = await generateNextBeat(choice, gameState, selectedTheme);
      setGameState(nextBeat.new_state);
      setCurrentBeat(nextBeat);

      // Fetch image in background
      generateSceneImage(nextBeat.image_prompt).then(img => {
        if (img) setCurrentImage(img);
      });

    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const saveGame = () => {
    if (!gameState || !currentBeat) return;

    const saveData: SaveData = {
      gameState,
      currentBeat,
      currentImage,
      selectedTheme,
      timestamp: Date.now()
    };

    try {
      localStorage.setItem('chronos_save', JSON.stringify(saveData));
      setHasSave(true);
    } catch (e) {
      console.error("Failed to save game", e);
    }
  };

  const loadGame = () => {
    try {
      const json = localStorage.getItem('chronos_save');
      if (!json) return;

      const data = JSON.parse(json) as SaveData;
      setGameState(data.gameState);
      setCurrentBeat(data.currentBeat);
      setCurrentImage(data.currentImage);
      setSelectedTheme(data.selectedTheme);
      setAppStatus(AppStatus.PLAYING);
    } catch (e) {
      console.error("Failed to load save", e);
      setHasSave(false);
      localStorage.removeItem('chronos_save');
    }
  };

  const resetGame = () => {
    setGameState(null);
    setCurrentBeat(null);
    setCurrentImage(null);
    setAppStatus(AppStatus.MENU);
  };

  return (
    <GameContext.Provider value={{
      gameState,
      currentBeat,
      currentImage,
      appStatus,
      isLoading,
      selectedTheme,
      hasSave,
      enterThemeSelection,
      startGame,
      makeChoice,
      resetGame,
      saveGame,
      loadGame
    }}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within GameProvider");
  return context;
};

import React, { useEffect, useState } from 'react';
import { GameProvider, useGame } from './context/GameContext';
import { MonetizationProvider, useMonetization } from './context/MonetizationContext';
import { SplashScreen } from './components/SplashScreen';
import { StoryView } from './components/StoryView';
import { ThemeSelector } from './components/ThemeSelector';
import { Paywall } from './components/Paywall';
import { AdOverlay } from './components/AdOverlay';
import { AppStatus } from './types';

const GameContent: React.FC = () => {
  const { appStatus, enterThemeSelection, resetGame, isLoading, saveGame, loadGame, hasSave } = useGame();
  const { isAdShowing, isPremium, showPaywallModal, openPaywall, closePaywall } = useMonetization();
  const [showSplash, setShowSplash] = useState(true);
  const [saveNotification, setSaveNotification] = useState(false);

  // Handle Splash Screen Logic
  useEffect(() => {
    const timer = setTimeout(() => {
      setShowSplash(false);
    }, 2500); // 2.5s splash
    return () => clearTimeout(timer);
  }, []);

  const handleSave = () => {
    saveGame();
    setSaveNotification(true);
    setTimeout(() => setSaveNotification(false), 2000);
  };

  if (showSplash) {
    return <SplashScreen />;
  }

  // THEME SELECTION STATE
  if (appStatus === AppStatus.THEME_SELECT) {
    return (
      <div className="w-full h-screen bg-black">
        <ThemeSelector />
        {isAdShowing && <AdOverlay />}
      </div>
    );
  }

  // MENU STATE
  if (appStatus === AppStatus.MENU || appStatus === AppStatus.SPLASH) {
     return (
       <div className="relative w-full h-screen bg-black flex flex-col items-center justify-center overflow-hidden">
         {/* Abstract BG */}
         <div className="absolute inset-0 bg-[url('https://picsum.photos/1920/1080?grayscale&blur=8')] bg-cover opacity-30" />

         <div className="z-10 text-center space-y-8 p-4">
           <h1 className="text-6xl md:text-8xl font-bold cinematic-text text-white tracking-tighter mb-4">CHRONOS</h1>
           <p className="text-xl text-gray-400 max-w-md mx-auto">Infinite possibilities. One timeline. Yours.</p>

           <div className="flex flex-col gap-4 w-full max-w-xs mx-auto">
             {hasSave && (
               <button 
                 onClick={loadGame}
                 disabled={isLoading}
                 className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-bold tracking-widest transition-all rounded-sm flex justify-center items-center gap-2 border border-indigo-400/50 shadow-[0_0_15px_rgba(79,70,229,0.5)]"
               >
                   CONTINUE TIMELINE
               </button>
             )}

             <button 
               onClick={enterThemeSelection}
               disabled={isLoading}
               className={`w-full py-4 bg-white text-black font-bold tracking-widest transition-all rounded-sm flex justify-center items-center gap-2 ${isLoading ? 'opacity-70 cursor-not-allowed' : 'hover:bg-gray-200'}`}
             >
                 {hasSave ? 'NEW TIMELINE' : 'BEGIN STORY'}
             </button>

             {!isPremium && (
                <button 
                  onClick={openPaywall}
                  disabled={isLoading}
                  className="w-full py-4 border border-white/20 text-white hover:bg-white/10 transition-colors rounded-sm text-sm tracking-widest disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  REMOVE ADS
                </button>
             )}
           </div>
         </div>

         {showPaywallModal && <Paywall onClose={closePaywall} />}
       </div>
     );
  }

  // PLAYING STATE
  return (
    <div className="w-full h-screen bg-black relative">
      <StoryView />

      {/* Controls Top Right */}
      <div className="fixed top-4 right-4 z-40 flex items-center gap-3">
        {/* Save Notification */}
        <div className={`transition-all duration-500 ${saveNotification ? 'opacity-100 translate-x-0' : 'opacity-0 translate-x-4'} pointer-events-none`}>
          <span className="text-[10px] uppercase tracking-widest text-emerald-400 bg-black/50 backdrop-blur px-3 py-1 rounded-full border border-emerald-500/30">
            Checkpoint Saved
          </span>
        </div>

        <button 
          onClick={handleSave}
          disabled={isLoading}
          className="w-10 h-10 flex items-center justify-center rounded-full bg-black/50 hover:bg-black/80 text-white border border-white/20 transition-all hover:scale-110 active:scale-95 disabled:opacity-50"
          title="Save Progress"
        >
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-4 h-4">
            <path strokeLinecap="round" strokeLinejoin="round" d="M16.5 3.75V16.5L12 14.25 7.5 16.5V3.75m9 0H18A2.25 2.25 0 0 1 20.25 6v12A2.25 2.25 0 0 1 18 20.25H6A2.25 2.25 0 0 1 3.75 18V6A2.25 2.25 0 0 1 6 3.75h1.5m9 0h-9" />
          </svg>
        </button>

        <button 
          onClick={resetGame}
          className="w-10 h-10 flex items-center justify-center rounded-full bg-black/50 hover:bg-red-900/50 text-white border border-white/20 transition-transform hover:rotate-90 hover:border-red-500/50"
          title="Exit to Menu"
        >
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-4 h-4">
            <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
      </div>

      {/* Global Overlays */}
      {isAdShowing && <AdOverlay />}
      {showPaywallModal && <Paywall onClose={closePaywall} />}
    </div>
  );
};

const App: React.FC = () => {
  return (
    <MonetizationProvider>
      <GameProvider>
        <GameContent />
      </GameProvider>
    </MonetizationProvider>
  );
};

export default App;

