                    <span className="block text-[10px] tracking-[0.2em] text-gray-500 mb-1 md:mb-2 group-hover:text-indigo-300 transition-colors uppercase">Intervention {idx + 1}</span>
                    <span className="text-base md:text-lg lg:text-xl font-medium text-gray-200 group-hover:text-white font-serif">{opt.label}</span>
                </button>
                ))
            )}
            </div>
        </div>
      </div>
    </div>
  );
};

